<?php
/** Tour card. */
defined( 'ABSPATH' ) || exit;
$id = get_the_ID(); $days = absint( wma_trip_meta( 'days', $id ) ); $nights = absint( wma_trip_meta( 'nights', $id ) ); $styles = get_the_terms( $id, 'wma_style' );
?>
<article class="wma-trip-card" data-wma-reveal><a class="wma-trip-card-image" href="<?php the_permalink(); ?>"><img src="<?php echo esc_url( wma_image_url( $id ) ); ?>" alt="<?php echo esc_attr( get_the_title() ); ?>" loading="lazy" width="760" height="540"><?php if ( $styles && ! is_wp_error( $styles ) ) : ?><span class="wma-trip-card-label"><?php echo esc_html( $styles[0]->name ); ?></span><?php endif; ?></a><div class="wma-trip-card-body"><div class="wma-trip-card-meta"><span><?php echo esc_html( wma_trip_price( $id ) ); ?></span><?php if ( $days ) : ?><span><?php echo esc_html( sprintf( _n( '%d day', '%d days', $days, 'wild-morocco-adventures' ), $days ) ); ?><?php echo $nights ? ' / ' . esc_html( sprintf( _n( '%d night', '%d nights', $nights, 'wild-morocco-adventures' ), $nights ) ) : ''; ?></span><?php endif; ?></div><h3><a href="<?php the_permalink(); ?>"><?php the_title(); ?></a></h3><?php if ( has_excerpt() ) : ?><p><?php echo esc_html( get_the_excerpt() ); ?></p><?php endif; ?><a class="wma-text-link" href="<?php the_permalink(); ?>"><?php esc_html_e( 'Discover this journey', 'wild-morocco-adventures' ); ?> <span aria-hidden="true">→</span></a></div></article>
